public class ProfileStatusCommandTests
{
    private MockRepository mocks = new MockRepository(MockBehavior.Strict);

    public static IEnumerable<object[]> ValidArgs()
    {
        yield return new object[] { "pro",      "status", };
        yield return new object[] { "pro",      "sta",    };
        yield return new object[] { "profile",  "status", };
        yield return new object[] { "profiles", "status", };
        yield return new object[] { "Profile",  "Status", };
    }

    public static IEnumerable<object[]> InvalidArgs()
    {
        yield return new object[] { "pro",  "list",   };
        yield return new object[] { "pro",  "add",    };
        yield return new object[] { "act",  "status", };
        yield return new object[] { "status",         };
    }

    [Theory, MemberData(nameof(ValidArgs))]
    public void ParseArgs_Valid(string arg0, string arg1)
    {
        var app = MakeApp();
        var target = new ProfileStatusCommand(app.Object);
        var result = target.ParseArgs(app.Object, new[] { arg0, arg1 }, out int consumed, out Command? command);
        Assert.True(result);
        Assert.NotNull(command);
        Assert.Equal(2, consumed);
    }

    [Theory, MemberData(nameof(InvalidArgs))]
    public void ParseArgs_Invalid(params string[] args)
