    [Fact]
    public async Task Run_NoProfile_PrintsMessage()
    {
        var app = MakeApp(profile: null);
        var target = new ProfileStatusCommand(app.Object);

        var output = await CaptureRun(target);

        Assert.Contains("No profile loaded", output);
    }

    [Fact]
    public async Task Run_MinimalProfile_ShowsFileAndUsername()
    {
        var profile = new MynatimeProfile();
        profile.LoginUsername = "user@example.com";
        var app = MakeApp(profile);
        var target = new ProfileStatusCommand(app.Object);

        var output = await CaptureRun(target);

        Assert.Contains("user@example.com", output);
        Assert.Contains("(unsaved)", output);
        Assert.Contains("none", output);       // session
    }

    [Fact]
    public async Task Run_WithIdentity_ShowsNameAndRoles()
    {
        var profile = new MynatimeProfile();
        profile.LoginUsername = "user@example.com";
        profile.UserId = "12345";
        profile.Identity = new JObject
        {
            ["email"]     = "user@example.com",
            ["name"]      = "Antoine SOTTIAU",
            ["roles"]     = new JArray("ROLE_USER_MT", "ROLE_MANAGER_MT"),
        };
        var app = MakeApp(profile);
        var target = new ProfileStatusCommand(app.Object);

        var output = await CaptureRun(target);

        Assert.Contains("Antoine SOTTIAU", output);
        Assert.Contains("12345", output);
        Assert.Contains("ROLE_USER_MT", output);
        Assert.Contains("ROLE_MANAGER_MT", output);
    }

    [Fact]
    public async Task Run_WithCookies_ShowsActiveSession()
    {
        var profile = new MynatimeProfile();
        profile.LoginUsername = "user@example.com";
        profile.Cookies = new JArray(
            new JObject { ["Name"] = "PHPSESSID", ["Value"] = "abc" },
            new JObject { ["Name"] = "REMEMBERME", ["Value"] = "xyz" });
        var app = MakeApp(profile);
        var target = new ProfileStatusCommand(app.Object);

        var output = await CaptureRun(target);

        Assert.Contains("active", output);
        Assert.Contains("2 cookies", output);
    }

    [Fact]
    public async Task Run_WithCategories_ShowsCountAndDate()
    {
        var profile = new MynatimeProfile();
        profile.LoginUsername = "user@example.com";
        profile.Data!.ActivityCategories!.Add(new MynatimeProfileDataActivityCategory("1", "Internal"));
        profile.Data.ActivityCategories.Add(new MynatimeProfileDataActivityCategory("2", "Project"));
        profile.Data.ActivityCategories.LastUpdated = new DateTime(2026, 4, 1, 0, 0, 0, DateTimeKind.Utc);
        var app = MakeApp(profile);
        var target = new ProfileStatusCommand(app.Object);

        var output = await CaptureRun(target);

        Assert.Contains("2 categories", output);
        Assert.Contains("2026-04-01", output);
    }

    [Fact]
    public async Task Run_WithPendingAndCommits_ShowsCounts()
    {
        var profile = new MynatimeProfile();
        profile.LoginUsername = "user@example.com";
        profile.Transaction!.Add(new MynatimeProfileTransactionItem());
        profile.Transaction.Add(new MynatimeProfileTransactionItem());
        profile.Commits!.Add(new MynatimeProfileTransactionItem());
        var app = MakeApp(profile);
        var target = new ProfileStatusCommand(app.Object);

        var output = await CaptureRun(target);

        Assert.Contains("2 items", output);  // pending
        Assert.Contains("1 item",  output);  // commits (singular)
    }

    private Mock<IConsoleApp> MakeApp(MynatimeProfile? profile = null)
    {
        var mock = this.mocks.Create<IConsoleApp>();
        mock.SetupGet(x => x.CurrentProfile).Returns(profile);
        return mock;
    }

    private static async Task<string> CaptureRun(Command command)
    {
        var original = Console.Out;
        using var writer = new StringWriter();
        Console.SetOut(writer);
        try
        {
            await command.Run();
        }
        finally
        {
            Console.SetOut(original);
        }

        return writer.ToString();
    }
}
